// 当前选中的国家ID
let selectedId = null;

// 抽取添加国家的函数
function addCountryPath(country, index) {
    const map = document.getElementById('map');
    const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
    
    path.setAttribute('d', countryPaths[index]);
    path.setAttribute('fill', '#E8E8E8');
    path.setAttribute('stroke', '#888888');
    path.setAttribute('stroke-width', '5');
    path.setAttribute('class', 'country');
    path.setAttribute('data-id', country.id);
    
    //鼠标悬停
    path.addEventListener('mouseenter', function() {
        if (!this.classList.contains('selected')) {
            this.setAttribute('fill', country.color);  // 变为国家颜色
        }
    });
    
    // 鼠标离开：恢复淡灰色
    path.addEventListener('mouseleave', function() {
        if (!this.classList.contains('selected')) {
            this.setAttribute('fill', '#E8E8E8');       // 恢复淡灰色
        }
    });
    
    // 点击事件
    path.addEventListener('click', function() {
        handleCountryClick(country.id, this);
    });
    
    map.appendChild(path);
}


// 初始化地图
function initMap() {
    console.log('初始化地图...');
    const map = document.getElementById('map');
    if (!map) {
        console.error('找不到 map 元素');
        return;
    }
    
    // 清空地图
    map.innerHTML = '';
    
    // 图层顺序：粉色(9) > 紫色(5) > 其他国家
    const countryOrder = [1, 2, 3, 4, 5, 6, 7, 8];
    
    // 按照指定顺序添加国家
    countryOrder.forEach(id => {
        const country = countries.find(c => c.id === id);
        const index = countries.findIndex(c => c.id === id);
        if (country && index !== -1) {
            addCountryPath(country, index);
        }
    });
    
    // 等待一下确保所有path都已渲染，然后添加图标
    setTimeout(addCountryIcons, 100);
    
    console.log('地图初始化完成，共添加', countries.length, '个国家');
}

// 添加国家图标
function addCountryIcons() {
    const map = document.getElementById('map');
    
    // 同样按照图层顺序添加图标
    const iconOrder = [1, 2, 3, 4, 5, 6, 7, 8];
    
    iconOrder.forEach(id => {
        const country = countries.find(c => c.id === id);
        if (!country) return;
        
        // 找到对应的国家path
        const path = document.querySelector(`.country[data-id="${country.id}"]`);
        if (!path) return;
        
        // 获取path的中心点
        const bbox = path.getBBox();
        let centerX = bbox.x + bbox.width / 2;
        let centerY = bbox.y + bbox.height / 2;
        
        // ===== 为特定国家调整图标位置 =====
        if (country.id === 7) {  // 黑国
            centerX = centerX +85;
            centerY = centerY +60;
        }
        if (country.id === 2) {  // 橙国
            centerX = centerX - 0;
            centerY = centerY +70;
        }
        if (country.id === 6) {  // 紫国
            centerX = centerX +60;
            centerY = centerY +95;
        }
        if (country.id === 3) {  // 黄国
            centerX = centerX -120;
            centerY = centerY +70;
        }
        if (country.id === 8) {  // 白国
            centerX = centerX +360;
            centerY = centerY +70;
        }
         if (country.id === 1) {  // 红国
            centerX = centerX +90;
            centerY = centerY +70;
        }
         if (country.id === 5) {  // 青国
            centerX = centerX +65;
            centerY = centerY +70;
        }
         if (country.id === 4) {  // 绿国
            centerX = centerX +360;
            centerY = centerY -80;
        }
        // 创建图标组
        const iconGroup = document.createElementNS('http://www.w3.org/2000/svg', 'g');
        iconGroup.setAttribute('class', 'country-icon-group');
        iconGroup.setAttribute('data-id', country.id);
        iconGroup.setAttribute('pointer-events', 'none');
        
        // 添加图标图片
        const iconImage = document.createElementNS('http://www.w3.org/2000/svg', 'image');
        iconImage.setAttribute('href', `icons/${country.id}.png`);
        iconImage.setAttribute('x', centerX - 150);
        iconImage.setAttribute('y', centerY - 150);
        iconImage.setAttribute('width', '160');
        iconImage.setAttribute('height', '160');
        iconImage.setAttribute('preserveAspectRatio', 'xMidYMid meet');
        iconImage.setAttribute('pointer-events', 'none');
        iconGroup.appendChild(iconImage);
        
        map.appendChild(iconGroup);
    });
    
    console.log('图标添加完成');
}

// 处理点击 - 修复版（保护粉色和紫色图层）
function handleCountryClick(id, element) {
    // 如果点击的是同一个国家
    if (selectedId === id) {
        element.classList.remove('selected');
        element.style.filter = '';
        selectedId = null;
        closePopup();  // 关闭弹窗
        return;
    }
    
    // 如果之前有选中的国家，取消它的选中状态
    if (selectedId) {
        const prevElement = document.querySelector(`.country[data-id="${selectedId}"]`);
        if (prevElement) {
            prevElement.classList.remove('selected');
            prevElement.style.filter = '';
        }
    }

    // 选中新国家
    element.classList.add('selected');
    selectedId = id;
    
    // 显示图片弹窗
    showCountryImage(id);
}


// ===== 图片弹窗功能 =====
function showCountryImage(id) {
    const country = countries.find(c => c.id === id);
    if (!country) return;
    
    const popup = document.getElementById('imagePopup');
    const popupImage = document.getElementById('popupImage');
    const popupCaption = document.getElementById('popupCaption');
    
    // 隐藏标题和战场栏
    const title = document.querySelector('.title');
    const battleSection = document.querySelector('.battle-section');
    if (title) title.style.visibility = 'hidden';
    if (battleSection) battleSection.style.visibility = 'hidden';
    
    popupImage.src = country.image;
    popupImage.alt = country.name;
    popupCaption.textContent = country.name;
    
    popup.classList.add('show');
}

function showUndergroundCountryInfo() {
    const popup = document.getElementById('imagePopup');
    const popupImage = document.getElementById('popupImage');
    const popupCaption = document.getElementById('popupCaption');
    
    const title = document.querySelector('.title');
    const battleSection = document.querySelector('.battle-section');
    if (title) title.style.visibility = 'visibility';
    if (battleSection) battleSection.style.visibility = 'visibility';

    popupImage.src = undergroundCountry.image;
    popupImage.alt = undergroundCountry.name;
    popupCaption.textContent = undergroundCountry.name;
    
    popup.classList.add('show');
}

function closePopup() {
    const popup = document.getElementById('imagePopup');
    popup.classList.remove('show');
    
    // 恢复显示标题和战场栏
    const title = document.querySelector('.title');
    const battleSection = document.querySelector('.battle-section');
    if (title) title.style.visibility = 'visible';
    if (battleSection) battleSection.style.visibility = 'visible';
}

// 关闭弹窗事件
document.addEventListener('DOMContentLoaded', function() {
    const popup = document.getElementById('imagePopup');
    if (popup) {
        popup.addEventListener('click', function(event) {
            if (event.target === this) {
                closePopup();
            }
        });
    }
    
    const closeBtn = document.getElementById('popupClose');
    if (closeBtn) {
        closeBtn.addEventListener('click', closePopup);
    }
});

// ESC键关闭弹窗
document.addEventListener('keydown', function(event) {
    if (event.key === 'Escape') {
        const popup = document.getElementById('imagePopup');
        if (popup && popup.classList.contains('show')) {
            closePopup();
        }
    }
});

// ===== 战场卡片点击弹窗功能 =====
function initBattleCards() {
    const battleCards = document.querySelectorAll('.battle-card');
    const battlePopup = document.getElementById('battlePopup');
    const battlePopupImage = document.getElementById('battlePopupImage');
    
    battleCards.forEach(card => {
        card.addEventListener('click', function(event) {
            event.stopPropagation();
            const imgPath = this.getAttribute('data-battle-img');
            if (imgPath) {
                battlePopupImage.src = imgPath;
                battlePopupImage.alt = this.querySelector('.battle-name').textContent;
                battlePopup.classList.add('show');
            }
        });
    });
    
    if (battlePopup) {
        battlePopup.addEventListener('click', function(event) {
            if (event.target === this) {
                battlePopup.classList.remove('show');
            }
        });
    }
}

// ESC键关闭战场弹窗
document.addEventListener('keydown', function(event) {
    if (event.key === 'Escape') {
        const battlePopup = document.getElementById('battlePopup');
        if (battlePopup && battlePopup.classList.contains('show')) {
            battlePopup.classList.remove('show');
        }
    }
});

// ===== 蓝国国徽按钮 =====
const undergroundEmblem = document.getElementById('undergroundEmblem');
if (undergroundEmblem) {
    undergroundEmblem.addEventListener('click', function() {
        showUndergroundCountryInfo();
    });
}

// ===== 战场图片缩放和拖动功能 =====
let currentScale = 1;
let currentTranslate = { x: 0, y: 0 };
let isDragging = false;
let dragStart = { x: 0, y: 0 };
let translateStart = { x: 0, y: 0 };

const viewer = document.getElementById('imageViewer');
const viewerImage = document.getElementById('battlePopupImage');
const battlePopup = document.getElementById('battlePopup');
const battlePopupClose = document.getElementById('battlePopupClose');

// 重置图片变换
function resetImageTransform() {
    currentScale = 1;
    currentTranslate = { x: 0, y: 0 };
    updateImageTransform();
}

// 更新图片变换
function updateImageTransform() {
    if (viewerImage) {
        viewerImage.style.transform = `translate(${currentTranslate.x}px, ${currentTranslate.y}px) scale(${currentScale})`;
    }
}

// 滚轮缩放
function handleWheelZoom(event) {
    if (!battlePopup || !battlePopup.classList.contains('show')) return;
    
    event.preventDefault();
    
    const delta = event.deltaY > 0 ? -0.1 : 0.1;
    const newScale = Math.min(Math.max(currentScale + delta, 0.5), 5);
    
    if (newScale !== currentScale) {
        const rect = viewerImage.getBoundingClientRect();
        const mouseX = event.clientX - rect.left;
        const mouseY = event.clientY - rect.top;
        
        const scaleChange = newScale / currentScale;
        
        currentTranslate.x = mouseX - (mouseX - currentTranslate.x) * scaleChange;
        currentTranslate.y = mouseY - (mouseY - currentTranslate.y) * scaleChange;
        
        currentScale = newScale;
        updateImageTransform();
    }
}

// 鼠标拖动平移
function startDrag(event) {
    if (!battlePopup || !battlePopup.classList.contains('show')) return;
    if (event.button !== 0) return;
    
    isDragging = true;
    dragStart = { x: event.clientX, y: event.clientY };
    translateStart = { ...currentTranslate };
    if (viewer) viewer.style.cursor = 'grabbing';
    event.preventDefault();
}

function onDrag(event) {
    if (!isDragging) return;
    
    const dx = event.clientX - dragStart.x;
    const dy = event.clientY - dragStart.y;
    
    currentTranslate.x = translateStart.x + dx;
    currentTranslate.y = translateStart.y + dy;
    
    updateImageTransform();
}

function endDrag() {
    isDragging = false;
    if (viewer) viewer.style.cursor = 'grab';
}

// 关闭弹窗时的重置
function resetOnClose() {
    resetImageTransform();
    if (viewer) {
        viewer.scrollTop = 0;
        viewer.scrollLeft = 0;
    }
}

// 绑定事件
if (viewer) {
    viewer.addEventListener('wheel', handleWheelZoom, { passive: false });
    viewer.addEventListener('mousedown', startDrag);
    window.addEventListener('mousemove', onDrag);
    window.addEventListener('mouseup', endDrag);
    viewer.style.cursor = 'grab';
}

// 关闭按钮事件
if (battlePopupClose) {
    battlePopupClose.addEventListener('click', function(event) {
        event.stopPropagation();
        if (battlePopup) battlePopup.classList.remove('show');
        resetOnClose();
    });
}

// 点击背景关闭
if (battlePopup) {
    battlePopup.addEventListener('click', function(event) {
        if (event.target === this) {
            battlePopup.classList.remove('show');
            resetOnClose();
        }
    });
}

// 修改 initBattleCards 函数
function initBattleCards() {
    const battleCards = document.querySelectorAll('.battle-card');
    
    battleCards.forEach(card => {
        card.addEventListener('click', function(event) {
            event.stopPropagation();
            const imgPath = this.getAttribute('data-battle-img');
            if (imgPath && viewerImage && battlePopup) {
                viewerImage.src = imgPath;
                battlePopup.classList.add('show');
                resetOnClose();
            }
        });
    });
}

// ===== 汉堡菜单交互 =====
const menuIcon = document.getElementById('menuIcon');
const dropdownMenu = document.getElementById('dropdownMenu');

if (menuIcon && dropdownMenu) {
    menuIcon.addEventListener('click', function(event) {
        event.stopPropagation();
        dropdownMenu.classList.toggle('show');
    });
    
    document.addEventListener('click', function(event) {
        if (!menuIcon.contains(event.target) && !dropdownMenu.contains(event.target)) {
            dropdownMenu.classList.remove('show');
        }
    });
    
    const menuItems = document.querySelectorAll('.menu-item');
    menuItems.forEach((item) => {
        item.addEventListener('click', function() {
            dropdownMenu.classList.remove('show');
        });
    });
}

// 页面加载完成后初始化
window.onload = function() {
    initMap();
    initBattleCards();
};